class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

# Build list from array
def build(vals):
    dummy = ListNode(0)
    cur = dummy
    for v in vals:
        cur.next = ListNode(v)
        cur = cur.next
    return dummy.next

# Convert to list
def to_list(head):
    result = []
    while head:
        result.append(head.val)
        head = head.next
    return result

# Insert after a node — O(1)
def insert_after(node, val):
    new_node = ListNode(val, node.next)
    node.next = new_node

# Delete next node — O(1)
def delete_next(node):
    if node.next:
        node.next = node.next.next

import heapq

# Merge two sorted lists — O(N+M) time, O(1) space
def merge_two(l1, l2):
    dummy = cur = ListNode(0)
    while l1 and l2:
        if l1.val <= l2.val:
            cur.next = l1; l1 = l1.next
        else:
            cur.next = l2; l2 = l2.next
        cur = cur.next
    cur.next = l1 or l2  # attach remaining
    return dummy.next

# Merge K sorted lists — O(N log K) using heap
def merge_k_lists(lists):
    dummy = cur = ListNode(0)
    # Heap stores (value, list_index, node)
    # list_index breaks ties when values equal (avoids comparing ListNodes)
    heap = []
    for i, node in enumerate(lists):
        if node:
            heapq.heappush(heap, (node.val, i, node))

    while heap:
        val, i, node = heapq.heappop(heap)
        cur.next = node; cur = cur.next
        if node.next:
            heapq.heappush(heap, (node.next.val, i, node.next))

    return dummy.next
